# Unit Tests for <B10>

The function <B10> is a constant function that always returns 10. Below is a comprehensive test suite to verify its behavior.

```python
import unittest

def B10(x):
    return 10

class TestB10Function(unittest.TestCase):

    def test_positive_integer(self):
        """Test with positive integer input."""
        self.assertEqual(B10(42), 10)

    def test_negative_integer(self):
        """Test with negative integer input."""
        self.assertEqual(B10(-17), 10)

    def test_zero(self):
        """Test with zero as input."""
        self.assertEqual(B10(0), 10)

    def test_large_number(self):
        """Test with large integer input."""
        self.assertEqual(B10(999999), 10)

    def test_consistency(self):
        """Test that multiple calls with same input return same value."""
        self.assertEqual(B10(8), B10(8))

    def test_different_inputs_same_output(self):
        """Test that different inputs produce identical output."""
        self.assertEqual(B10(1), B10(100))
        self.assertEqual(B10(-50), B10(50))

if __name__ == '__main__':
    unittest.main()
```
